import flask
from flask import Flask, jsonify, request
import logging

app = Flask(__name__)

# Setup logging configuration
logging.basicConfig(filename='app.log', filemode='w', format='%(asctime)s - %(message)s')
logger = logging.getLogger()
logger.setLevel(logging.DEBUG)

@app.route('/api/v1/users', methods=['GET'])
def get_users():
    # Log the request headers and body data for debugging
    logger.info('Request headers: ' + str(request.headers))
    logger.info('Request body: ' + str(request.data))

    # Log user information for troubleshooting failed logins
    if request.method == 'POST':
        username = request.json['username']
        password = request.json['password']
        logger.info('User ' + username + ' attempted to login with password ' + password)

    # Return a list of users for the GET request
    return jsonify([{'name': 'John Doe', 'age': 30}, {'name': 'Jane Doe', 'age': 25}])

if __name__ == '__main__':
    app.run(debug=True)